sourcePacket.value:
{ $waveDisplayMode ->
  [amplitude] Round packet of solid { a11y_sourceWaveFragments_lowercaseColor } wave
  moves toward { a11y_sourceWaveFragments_slitTarget }
 *[electricField] Round packet of { a11y_sourceWaveFragments_lowercaseColor } and black
  waves moves toward { a11y_sourceWaveFragments_slitTarget }
  { a11y_sourceWaveFragments_wavePeakSpacing }
  [realPart] Round packet of { a11y_sourceWaveFragments_lowercaseColor } and black
  waves moves toward { a11y_sourceWaveFragments_slitTarget }
  { a11y_sourceWaveFragments_wavePeakSpacing }
  [imaginaryPart] Round packet of { a11y_sourceWaveFragments_lowercaseColor } and black
  waves moves toward { a11y_sourceWaveFragments_slitTarget }
  { a11y_sourceWaveFragments_wavePeakSpacing }
}

sourceBeam.value:
{ $isEmitting ->
  [false] No beam is visible in the wave area.
 *[true] { $waveDisplayMode ->
    [amplitude] Solid { a11y_sourceWaveFragments_lowercaseColor } wave moves toward
    { a11y_sourceWaveFragments_slitTarget }
   *[electricField] { a11y_sourceWaveFragments_capitalizedColorAndBlack } plane wave fronts
    move toward { a11y_sourceWaveFragments_slitTarget }
    { a11y_sourceWaveFragments_wavePeakSpacing }
    [realPart] { a11y_sourceWaveFragments_capitalizedColorAndBlack } plane wave fronts
    move toward { a11y_sourceWaveFragments_slitTarget }
    { a11y_sourceWaveFragments_wavePeakSpacing }
    [imaginaryPart] { a11y_sourceWaveFragments_capitalizedColorAndBlack } plane wave fronts
    move toward { a11y_sourceWaveFragments_slitTarget }
    { a11y_sourceWaveFragments_wavePeakSpacing }
  }
}

slitSeparationChanged.value:
{ $isRestarting ->
  [true] { $sourceRestartedResponse }
 *[false] Slit separation changed. Experiment changed. Previous hits cleared.
}

wavelengthChanged.value:
{ $isRestarting ->
  [true] { $sourceRestartedResponse }
 *[false] Wavelength changed. Experiment changed. Previous hits cleared.
}

screenCleared.value:
{ $isRestarting ->
  [true] { $sourceRestartedResponse }
 *[false] Wave area cleared. Sim still paused.
}

accessibleContextResponseExpanded.value:
{ $detectionMode ->
  [intensity] Dynamic graph of intensity pattern shown. { $graphState }
 *[hits] Dynamic histogram of hits data shown. { $graphState }
}

snapshotHitsDeveloping.value:
Individual impacts are gathering into distinct vertical bands, separated by regions with fewer particles. { $hitCount ->
    [one] Detector screen shows a total of 1 hit.
   *[other] Detector screen shows a total of { $hitCount } hits.
} { $spatialDescription }

snapshotHitsClear.value:
Distinct vertical bands fill the screen, with dense stripes separated by nearly empty gaps. { $hitCount ->
    [one] Detector screen shows a total of 1 hit.
   *[other] Detector screen shows a total of { $hitCount } hits.
} { $spatialDescription }

snapshotHitsSingleSlitClear.value:
Hits form a broad central band that tapers toward the edges. { $hitCount ->
    [one] Detector screen shows a total of 1 hit.
   *[other] Detector screen shows a total of { $hitCount } hits.
} { $spatialDescription }
